  // For other warnings, use the default warning handling\n        warn(warning);\n      },\n    },\n  },\n});\n",paraId:35,tocIndex:9},{value:"In v5, the built-in colors are: export type BuiltInPalette = 'spectral' | 'oranges' | 'greens' | 'blues';",paraId:36,tocIndex:10},{value:"The solution is as follows:",paraId:37,tocIndex:10},{value:"const graph = new Graph({\n  container: '#ID',\n  width: number,\n  height: number,\n  data,\n  node: {\n    palette: {\n      field: 'color',\n      // right\n      color: ['red', 'green', 'blue'],\n\n      // error\n      // color: 'red'\n    },\n  },\n});\n",paraId:38,tocIndex:10},{value:"In v5, built-in plugins include ",paraId:39,tocIndex:11},{value:"bubble-sets",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"edge-filter-lens",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"grid-line",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"background",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"contextmenu",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"fisheye",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"fullscreen",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"history",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"hull",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"legend",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"minimap",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"snapline",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"timebar",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"toolbar",paraId:39,tocIndex:11},{value:" ",paraId:39,tocIndex:11},{value:"tooltip",paraId:39,tocIndex:11},{value:" >",paraId:39,tocIndex:11},{value:"watermark",paraId:39,tocIndex:11},{value:". ",paraId:39,tocIndex:11},{value:"Detailed reference",paraId:39,tocIndex:11},{value:"Actual reason: The parent container of the ",paraId:40,tocIndex:11},{value:"graph",paraId:40,tocIndex:11},{value:" instance, ",paraId:40,tocIndex:11},{value:"<div ref={containerRef} />",paraId:40,tocIndex:11},{value:", does not have a height set, so the G6 Graph may not be able to calculate the correct size.",paraId:40,tocIndex:11},{value:"If you want to enable the ",paraId:40,tocIndex:11},{value:"grid-line",paraId:40,tocIndex:11},{value:" canvas plugin, you need to set the width and height of the parent element, which is not valid in the graph configuration",paraId:40,tocIndex:11},{value:".",paraId:40,tocIndex:11},{value:"Use ",paraId:41,tocIndex:12},{value:"new Graph({xxx})",paraId:41,tocIndex:12},{value:" uniformly.",paraId:41,tocIndex:12},{value:"In v5, built-in layouts include ",paraId:42,tocIndex:12},{value:"antv-dagre",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"combo-combined",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"compact-box",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"force-atlas2",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"circular",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"concentric",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"d3-force",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"dagre",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"dendrogram",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"force",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"fruchterman",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"grid",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"indented",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"mds",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"mindmap",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"radial",paraId:42,tocIndex:12},{value:" ",paraId:42,tocIndex:12},{value:"random",paraId:42,tocIndex:12},{value:". ",paraId:42,tocIndex:12},{value:"Specific reference",paraId:42,tocIndex:12},{value:"v5 merges the graph and tree graph, no longer creates the tree graph layout by instantiating ",paraId:43,tocIndex:12},{value:"G6.TreeGraph",paraId:43,tocIndex:12},{value:", and removes this method. For details, see ",paraId:43,tocIndex:12},{value:"Features - Merge Graph and Tree Graph",paraId:43,tocIndex:12},{value:"is configured ",paraId:44,tocIndex:13},{value:"portLinkToCenter",paraId:44,tocIndex:13},{value:" to ",paraId:44,tocIndex:13},{value:"true",paraId:44,tocIndex:13},{value:".",paraId:44,tocIndex:13},{value:"const graph = new Graph({\n  container: xxx,\n  node: {\n    type: 'rect',\n    style: {\n      portLinkToCenter: true,\n    },\n  },\n  edge: {\n    type: 'xxx',\n  },\n});\n",paraId:45,tocIndex:13},{value:"Implementation solution: ",paraId:46,tocIndex:14},{value:"#6347",paraId:46,tocIndex:14},{value:"const measureTextWidth = memoize(\n  (text: string, font: any = {}): TextMetrics => {\n    const { fontSize, fontFamily = 'sans-serif', fontWeight, fontStyle, fontVariant } = font;\n    const ctx = getCanvasContext();\n    // @see https://developer.mozilla.org/zh-CN/docs/Web/CSS/font\n    ctx.font = [fontStyle, fontWeight, fontVariant, `${fontSize}px`, fontFamily].join(' ');\n    return ctx.measureText(isString(text) ? text : '').width;\n  },\n  (text: string, font = {}) => [text, ...values(font)].join(''),\n);\n\nconst graph = new G6.Graph({\n    node: {\n          style: { size: d => [measureTextWidth(d.label, {...}) , xxx] },\n    }\n})\n",paraId:47,tocIndex:14},{value:"You can manually specify the ",paraId:48,tocIndex:15},{value:"IPointerEvent",paraId:48,tocIndex:15},{value:" type. For details, see ",paraId:48,tocIndex:15},{value:"#6346",paraId:49,tocIndex:15},{value:"import { NodeEvent } from '@antv/g6';\nimport type { IPointerEvent } from '@antv/g6';\n\ngraph.on(NodeEvent.CLICK, (event: IPointerEvent) => {\n  // handler\n});\n",paraId:50,tocIndex:15},{value:"Update the node data, set the ",paraId:51,tocIndex:16},{value:"combo",paraId:51,tocIndex:16},{value:" value to ",paraId:51,tocIndex:16},{value:"null",paraId:51,tocIndex:16},{value:".",paraId:51,tocIndex:16},{value:"graph.updateNodeData([{ id: 'node-id', combo: null }]);\n",paraId:52,tocIndex:16}]},10398:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(11517);const t=[{value:"Before using 3D capabilities, please install the 3D extension package first:",paraId:0,tocIndex:0},{value:"npm install @antv/g6-extension-3d --save\n",paraId:1,tocIndex:0},{value:"The extension package exports the following:",paraId:2,tocIndex:0},{value:"renderer: 3D renderer",paraId:3,tocIndex:0},{value:"Elements",paraId:4,tocIndex:0},{value:"Capsule: capsule node",paraId:5,tocIndex:0},{value:"Cone: cone node",paraId:5,tocIndex:0},{value:"Cube: cube node",paraId:5,tocIndex:0},{value:"Cylinder: cylinder node",paraId:5,tocIndex:0},{value:"Sphere: sphere node",paraId:5,tocIndex:0},{value:"Torus: torus node",paraId:5,tocIndex:0},{value:"Line3D: 3D line",paraId:5,tocIndex:0},{value:"Layout",paraId:6,tocIndex:0},{value:"D3Force3DLayout: 3D force-directed layout",paraId:7,tocIndex:0},{value:"Behaviors",paraId:8,tocIndex:0},{value:"DragCanvas3D: drag canvas",paraId:9,tocIndex:0},{value:"ObserveCanvas3D: observe canvas",paraId:9,tocIndex:0},{value:"RollCanvas3D: rotate canvas",paraId:9,tocIndex:0},{value:"ZoomCanvas3D: zoom canvas",paraId:9,tocIndex:0},{value:"Plugin",paraId:10,tocIndex:0},{value:"Light: light source",paraId:11,tocIndex:0},{value:"The following extensions are required:",paraId:12,tocIndex:1},{value:"renderer",paraId:13,tocIndex:1},{value:"at least one 3D node",paraId:13,tocIndex:1},{value:"Line3D",paraId:13,tocIndex:1},{value:"Light",paraId:13,tocIndex:1},{value:"The renderer does not need to be registered, it can be passed in during the instantiation of Graph.",paraId:14,tocIndex:1},{value:"Register as follows:",paraId:15,tocIndex:1},{value:"import { register, ExtensionCategory } from '@antv/g6';\nimport { Sphere, Line3D, Light } from '@antv/g6-extension-3d';\n\nregister(ExtensionCategory.NODE, 'sphere', Sphere);\nregister(ExtensionCategory.EDGE, 'line3d', Line3D);\nregister(ExtensionCategory.PLUGIN, 'light', Light);\n",paraId:16,tocIndex:1},{value:"After completing the above steps, you can create a 3D graph:",paraId:17,tocIndex:2},{value:"import { Graph } from '@antv/g6';\nimport { renderer } from '@antv/g6-extension-3d';\n\nconst graph = new Graph({\n  // ... other options\n  // use 3d renderer\n  renderer,\n  node: {\n    type: 'sphere', // use 3d node\n    style: {\n      materialType: 'phong', // use Phong material\n    },\n  },\n  edge: {\n    type: 'line3d', // use 3D edge\n  },\n  plugins: [\n    {\n      type: 'light', // Add light source\n      // configure directional light\n      directional: {\n        direction: [0, 0, 1],\n      },\n    },\n  ],\n});\n\ngraph.render();\n",paraId:18,tocIndex:2},{value:"You can also refer to:",paraId:19,tocIndex:2},{value:"Lite Solar System",paraId:20,tocIndex:2},{value:"3D Force Layout",paraId:21,tocIndex:2},{value:"@antv/g6",paraId:22,tocIndex:3},{value:" has a built-in registered plugin for CameraSetting for camera configuration, refer to ",paraId:22,tocIndex:3},{value:"plugin",paraId:23,tocIndex:3},{value:".",paraId:22,tocIndex:3},{value:"{\n  plugins: [\n    {\n      type: 'camera-setting',\n      projectionMode: 'perspective',\n      near: 0.1,\n      far: 1000,\n      fov: 45,\n      aspect: 1,\n    },\n  ];\n}\n",paraId:24,tocIndex:3}]},64315:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(99018);const t=[{value:"In general, if you are using modern build tools such as Webpack, Rollup, or ESBuild, you can easily build projects that depend on ",paraId:0},{value:"@antv/g6",paraId:0},{value:".",paraId:0},{value:"Some build tools, such as Vite, use ESBuild as the underlying tool, so you can refer to ESBuild's configuration.",paraId:1},{value:"Below are some example configurations that you can refer to when building your project. If you find that these configurations do not work properly, make sure that your build tool version is up to date.",paraId:2},{value:"Make sure that ",paraId:3,tocIndex:0},{value:"webpack",paraId:3,tocIndex:0},{value:" and ",paraId:3,tocIndex:0},{value:"webpack-cli",paraId:3,tocIndex:0},{value:" are installed in your project:",paraId:3,tocIndex:0},{value:"npm install webpack webpack-cli --save-dev\n",paraId:4,tocIndex:0},{value:"Refer to the following ",paraId:5,tocIndex:0},{value:"webpack.config.js",paraId:5,tocIndex:0},{value:" for configuration:",paraId:5,tocIndex:0},{value:"const path = require('path');\n\nmodule.exports = {\n  entry: './src/index.ts',\n  output: {\n    path: path.resolve(__dirname, 'dist'),\n    filename: 'index.js',\n  },\n  mode: 'production',\n};\n",paraId:6,tocIndex:0},{value:"Run the build command:",paraId:7,tocIndex:0},{value:"npx webpack\n",paraId:8,tocIndex:0},{value:"The above configuration works with ",paraId:9,tocIndex:0},{value:'"webpack": "^5.94.0"',paraId:9,tocIndex:0},{value:", ",paraId:9,tocIndex:0},{value:'"webpack-cli": "^5.1.4"',paraId:9,tocIndex:0},{value:".",paraId:9,tocIndex:0},{value:"⚠️ It is strongly recommended that projects use Webpack 5. If you are using Webpack 4, follow the steps below to configure:",paraId:10},{value:"Install the necessary dependencies: ",paraId:11},{value:"babel-loader",paraId:11},{value:" (<9), ",paraId:11},{value:"@babel/preset-env",paraId:11},{value:", ",paraId:11},{value:"@open-wc/webpack-import-meta-loader",paraId:11},{value:"If you are using TypeScript, you also need to install ",paraId:12},{value:"ts-loader",paraId:12},{value:".",paraId:12},{value:"npm install babel-loader@8 @babel/preset-env @open-wc/webpack-import-meta-loader --save-dev\n",paraId:13},{value:"Modify the ",paraId:14},{value:"webpack.config.js",paraId:14},{value:" configuration:",paraId:14},{value:"module.exports = {\n  entry: './src/index.js',\n  output: {\n    path: path.resolve(__dirname, 'dist'),\n    filename: 'index.js',\n  },\n  module: {\n    rules: [\n      {\n        test: /\\.js$/,\n        use: {\n          loader: 'babel-loader',\n          options: {\n            presets: ['@babel/preset-env'],\n          },\n        },\n      },\n      {\n        test: /\\.js$/,\n        loader: '@open-wc/webpack-import-meta-loader',\n      },\n    ],\n  },\n  mode: 'production',\n};\n",paraId:15},{value:"First, make sure that ",paraId:16,tocIndex:1},{value:"rollup",paraId:16,tocIndex:1},{value:" and the necessary plugins are installed in your project:",paraId:16,tocIndex:1},{value:"@rollup/plugin-commonjs",paraId:17,tocIndex:1},{value:": Used to load CommonJS modules",paraId:17,tocIndex:1},{value:"@rollup/plugin-node-resolve",paraId:17,tocIndex:1},{value:": Used to load Node.js modules",paraId:17,tocIndex:1},{value:"npm install rollup @rollup/plugin-commonjs @rollup/plugin-node-resolve --save-dev\n",paraId:18,tocIndex:1},{value:"Refer to the following ",paraId:19,tocIndex:1},{value:"rollup.config.js",paraId:19,tocIndex:1},{value:" for configuration:",paraId:19,tocIndex:1},{value:"const commonjs = require('@rollup/plugin-commonjs');\nconst resolve = require('@rollup/plugin-node-resolve');\n\nmodule.exports = {\n  input: 'src/index.ts',\n  output: {\n    file: 'dist/index.js',\n    format: 'umd',\n    name: 'project',\n  },\n  plugins: [resolve(), commonjs()],\n};\n",paraId:20,tocIndex:1},{value:"Run the build command:",paraId:21,tocIndex:1},{value:"npx rollup -c\n",paraId:22,tocIndex:1},{value:"First, make sure that ",paraId:23,tocIndex:2},{value:"esbuild",paraId:23,tocIndex:2},{value:" is installed in your project:",paraId:23,tocIndex:2},{value:"npm install esbuild --save-dev\n",paraId:24,tocIndex:2},{value:"Run the build command:",paraId:25,tocIndex:2},{value:"npx esbuild src/index.ts --bundle --outfile=dist/index.js\n",paraId:26,tocIndex:2}]},38932:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(50322);const t=[{value:"There are three coordinate systems in G6 5.0: Canvas, Viewport, and Client.",paraId:0,tocIndex:0},{value:"The coordinate system used when drawing G6 elements is not affected by camera zooming or panning. To change the position of an element, you need to directly modify the element's position properties (x/y/z).",paraId:1,tocIndex:1},{value:"The canvas space is theoretically infinite. In the initial state (no panning, zoom ratio is 1), the origin of the canvas coordinate system is located at the upper-left corner of the viewport.",paraId:2,tocIndex:1},{value:"The viewport coordinate system is the projection of the camera coordinate system. When the camera pans or zooms, the position of elements in the canvas will also change in the viewport coordinate system.",paraId:3,tocIndex:2},{value:"The size of the viewport is the size of the canvas DOM container. The origin of the viewport coordinate system is located at the upper-left corner of the viewport, with the x-axis pointing to the right and the y-axis pointing down.",paraId:4,tocIndex:2},{value:"The client coordinate system has the browser's upper-left corner as the origin, with the x-axis pointing to the right and the y-axis pointing down.",paraId:5,tocIndex:3},{value:"The following figure describes the relationship between the viewport coordinate system and the client coordinate system:",paraId:6,tocIndex:3},{value:"G6 provides methods for coordinate system conversion, making it easy to convert between different coordinate systems.",paraId:7,tocIndex:4},{value:"Canvas coordinate system to viewport coordinate system: ",paraId:8,tocIndex:4},{value:"getViewportByCanvas",paraId:9,tocIndex:4},{value:"Client coordinate system to canvas coordinate system: ",paraId:8,tocIndex:4},{value:"getCanvasByClient",paraId:10,tocIndex:4},{value:"Viewport coordinate system to canvas coordinate system: ",paraId:8,tocIndex:4},{value:"getCanvasByViewport",paraId:11,tocIndex:4},{value:"Canvas coordinate system to client coordinate system: ",paraId:8,tocIndex:4},{value:"getClientByCanvas",paraId:12,tocIndex:4},{value:"Other related APIs are also provided:",paraId:13,tocIndex:4},{value:"Get the viewport center in viewport coordinates: ",paraId:14,tocIndex:4},{value:"getCanvasCenter",paraId:15,tocIndex:4},{value:"Get the viewport center in canvas coordinates: ",paraId:14,tocIndex:4},{value:"getViewportCenter",paraId:16,tocIndex:4},{value:"Get the position of the graph origin in the viewport coordinate system: ",paraId:14,tocIndex:4},{value:"getPosition",paraId:17,tocIndex:4}]},23548:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(43778);const t=[{value:"G6 5.0 only provides an API for exporting the canvas as a Base64 image (",paraId:0},{value:"toDataURL",paraId:1},{value:"). If you need to download the image, you can use the following method:",paraId:0},{value:"async function downloadImage() {\n  const dataURL = await graph.toDataURL();\n  const [head, content] = dataURL.split(',');\n  const contentType = head.match(/:(.*?);/)![1];\n\n  const bstr = atob(content);\n  let length = bstr.length;\n  const u8arr = new Uint8Array(length);\n\n  while (length--) {\n    u8arr[length] = bstr.charCodeAt(length);\n  }\n\n  const blob = new Blob([u8arr], { type: contentType });\n\n  const url = URL.createObjectURL(blob);\n  const a = document.createElement('a');\n  a.href = url;\n  a.download = 'graph.png';\n  a.click();\n}\n",paraId:2},{value:"The exported image may not contain the complete canvas content; the export range only includes the content within the Graph canvas. Some plugins use custom containers, canvases, etc., and this content will not appear in the exported image.",paraId:3}]},42542:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(86698);const t=[{value:"The event system in G6 is encapsulated based on the event system of ",paraId:0,tocIndex:0},{value:"G",paraId:0,tocIndex:0},{value:", providing a wider range of event types and more convenient methods for event binding and unbinding.",paraId:0,tocIndex:0},{value:"The event types in G6 are mainly divided into the following categories:",paraId:1,tocIndex:1},{value:"Graph events",paraId:2,tocIndex:1},{value:"Canvas events",paraId:2,tocIndex:1},{value:"Element events",paraId:2,tocIndex:1},{value:"Graph events refer to events associated with the entire graph instance, such as the graph's rendering completion event, the graph's update event, etc. The complete list of graph events can be found at ",paraId:3,tocIndex:2},{value:"GraphEvent",paraId:4,tocIndex:2},{value:".",paraId:3,tocIndex:2},{value:"Listening to graph events is consistent with the default event listening method. For example, to listen to the graph's rendering completion event:",paraId:5,tocIndex:3},{value:"import { Graph, GraphEvent } from '@antv/g6';\n\nconst graph = new Graph({\n  // ...\n});\n\ngraph.on(GraphEvent.AFTER_RENDER, () => {\n  // event handler\n});\n",paraId:6,tocIndex:3},{value:"Canvas events refer to events associated with the canvas, such as the canvas's click event, the canvas's drag event, etc. The complete list of canvas events can be found at ",paraId:7,tocIndex:4},{value:"CanvasEvent",paraId:8,tocIndex:4},{value:".",paraId:7,tocIndex:4},{value:"For example, to listen to the canvas's click event:",paraId:9,tocIndex:5},{value:"import { Graph, CanvasEvent } from '@antv/g6';\n\nconst graph = new Graph({\n  // ...\n});\n\ngraph.on(CanvasEvent.CLICK, (event) => {\n  // event handler\n});\n",paraId:10,tocIndex:5},{value:"Element events primarily refer to events that are triggered on element objects, such as a node's drag event, an edge's click event, etc. Elements are categorized into three types: nodes (",paraId:11,tocIndex:6},{value:"node",paraId:11,tocIndex:6},{value:"), edges (",paraId:11,tocIndex:6},{value:"edge",paraId:11,tocIndex:6},{value:"), and combos (",paraId:11,tocIndex:6},{value:"combo",paraId:11,tocIndex:6},{value:"). The complete list of corresponding events can be found at: ",paraId:11,tocIndex:6},{value:"NodeEvent",paraId:12,tocIndex:6},{value:", ",paraId:11,tocIndex:6},{value:"EdgeEvent",paraId:13,tocIndex:6},{value:", ",paraId:11,tocIndex:6},{value:"ComboEvent",paraId:14,tocIndex:6},{value:".",paraId:11,tocIndex:6},{value:"Similar to canvas events, for example, to listen to a node's drag event and an edge's click event:",paraId:15,tocIndex:7},{value:"import { Graph, NodeEvent, EdgeEvent, ComboEvent } from '@antv/g6';\n\nconst graph = new Graph({\n  // ...\n});\n\ngraph.on(NodeEvent.DRAG, (event) => {\n  // event handler\n});\n\ngraph.on(EdgeEvent.CLICK, (event) => {\n  // event handler\n});\n\ngraph.on(ComboEvent.CLICK, (event) => {\n  // event handler\n});\n",paraId:16,tocIndex:7},{value:"G6 provides the following APIs for event listening and unlistening:",paraId:17,tocIndex:8},{value:"Add an event listener",paraId:18,tocIndex:9},{value:"const handler = (event) => {\n  // event handler\n};\n\ngraph.on('event_name', handler);\n",paraId:19,tocIndex:9},{value:"Remove an event listener",paraId:20,tocIndex:10},{value:"graph.off('event_name', handler);\n",paraId:21,tocIndex:10},{value:"When no arguments are passed, it will remove all event listeners:",paraId:22,tocIndex:10},{value:"graph.off();\n",paraId:23,tocIndex:10},{value:"Add a one-time event listener, which means the event listener will be automatically removed after the event is triggered",paraId:24,tocIndex:11},{value:"graph.once('event_name', handler);\n",paraId:25,tocIndex:11},{value:"If you want to manually trigger an event, you can use the ",paraId:26,tocIndex:12},{value:"emit",paraId:26,tocIndex:12},{value:" method:",paraId:26,tocIndex:12},{value:"graph.emit('event_name', {\n  // event data\n});\n",paraId:27,tocIndex:12}]},17905:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(72757);const t=[{value:"Why use iconfont? It offers great compatibility, a wide variety of icons, and multicolor options. For more details, please visit the ",paraId:0,tocIndex:0},{value:"Alibaba Iconfont Platform",paraId:0,tocIndex:0},{value:".",paraId:0,tocIndex:0},{value:"First, you need to download the desired font icons from the ",paraId:1,tocIndex:2},{value:"iconfont",paraId:1,tocIndex:2},{value:" website. Create a project, select the required icons, and then download the generated icon files.",paraId:1,tocIndex:2},{value:"After downloading, place the directory containing the icon font files (typically including ",paraId:2,tocIndex:3},{value:".eot",paraId:2,tocIndex:3},{value:", ",paraId:2,tocIndex:3},{value:".woff",paraId:2,tocIndex:3},{value:", ",paraId:2,tocIndex:3},{value:".ttf",paraId:2,tocIndex:3},{value:", and ",paraId:2,tocIndex:3},{value:".svg",paraId:2,tocIndex:3},{value:" files, as well as the ",paraId:2,tocIndex:3},{value:"iconfont.css",paraId:2,tocIndex:3},{value:" stylesheet) into your project.",paraId:2,tocIndex:3},{value:"You can choose how to include them. Below is an example of how to include them in HTML:",paraId:3,tocIndex:3},{value:"<head>\n  <style>\n    @import 'path-to-iconfont/iconfont.css';\n  </style>\n</head>\n",paraId:4,tocIndex:3},{value:"{\n  node: {\n    style: {\n      iconFontFamily: 'iconfont', // Corresponds to the `font-family` value in iconfont.css\n      iconText: '\\ue7f1', // Corresponds to the `content` value in iconfont.css, make sure to add `u`\n      iconFill: '#7863FF'\n    }\n  }\n}\n",paraId:5,tocIndex:4},{value:"getIcon()",paraId:6},{value:"To make it easier to retrieve icons, you can create a utility function ",paraId:7,tocIndex:5},{value:"getIcon",paraId:7,tocIndex:5},{value:". This function reads the icon information from the ",paraId:7,tocIndex:5},{value:"iconfont.json",paraId:7,tocIndex:5},{value:" file and returns the corresponding Unicode character. Note that manually concatenating Unicode (",paraId:7,tocIndex:5},{value:"\\\\u${icon.unicode}",paraId:7,tocIndex:5},{value:") won't work. Refer to ",paraId:7,tocIndex:5},{value:"MDN String.fromCodePoint",paraId:7,tocIndex:5},{value:" for details.",paraId:7,tocIndex:5},{value:"First, ensure you have an ",paraId:8,tocIndex:5},{value:"iconfont.json",paraId:8,tocIndex:5},{value:" file containing the detailed icon information.",paraId:8,tocIndex:5},{value:"import fonts from 'path-to-iconfont/iconfont.json';\n\nconst icons = fonts.glyphs.map((icon) => {\n  return {\n    name: icon.font_class,\n    unicode: String.fromCodePoint(icon.unicode_decimal), // `\\\\u${icon.unicode}`,\n  };\n});\n\nconst getIcon = (type) => {\n  const matchIcon = icons.find((icon) => {\n    return icon.name === type;\n  }) || { unicode: '', name: 'default' };\n  return matchIcon.unicode;\n};\n",paraId:9,tocIndex:5},{value:"Use it in your project:",paraId:10,tocIndex:5},{value:"{\n  node: {\n    style: {\n      iconFontFamily: \"iconfont\",\n      iconText: getIcon('logo')\n    }\n  }\n}\n",paraId:11,tocIndex:5}]},79115:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(39258);const t=[{value:"G6 uses Canvas as the default renderer, but also supports rendering with SVG and WebGL. To switch to the SVG or WebGL renderer, simply pass the ",paraId:0},{value:"renderer",paraId:0},{value:" parameter during initialization.",paraId:0},{value:"Install the renderer dependency:",paraId:1,tocIndex:0},{value:"npm install @antv/g-svg\n",paraId:2,tocIndex:0},{value:"Configure the renderer:",paraId:3,tocIndex:0},{value:"import { Renderer as SVGRenderer } from '@antv/g-svg';\nimport { Graph } from '@antv/g6';\n\nconst graph = new Graph({\n  // ... other options\n  // All canvases will use the SVG renderer here\n  renderer: () => new SVGRenderer(),\n});\n",paraId:4,tocIndex:0},{value:"Install the renderer dependency:",paraId:5,tocIndex:1},{value:"npm install @antv/g-webgl\n",paraId:6,tocIndex:1},{value:"Configure the renderer:",paraId:7,tocIndex:1},{value:"import { Renderer as WebGLRenderer } from '@antv/g-webgl';\nimport { Graph } from '@antv/g6';\n\nconst graph = new Graph({\n  // ... other options\n  // All canvases will use the WebGL renderer here\n  renderer: () => new WebGLRenderer(),\n});\n",paraId:8,tocIndex:1},{value:"G6 uses layered canvases for rendering, so ",paraId:9,tocIndex:2},{value:"renderer",paraId:9,tocIndex:2},{value:" is a callback function that takes the canvas type as a parameter and returns the renderer instance. If you want to use different renderers on different canvases, you can configure it like this:",paraId:9,tocIndex:2},{value:"import { Renderer as SVGRenderer } from '@antv/g-svg';\nimport { Renderer as WebGLRenderer } from '@antv/g-webgl';\n\nconst graph = new Graph({\n  // ... other options\n  renderer: (layer) => {\n    // The main canvas uses the WebGL renderer, and the other canvases use the SVG renderer\n    if (layer === 'main') return new WebGLRenderer();\n    return new SVGRenderer();\n  },\n});\n",paraId:10,tocIndex:2},{value:"G6 does not provide a API to switch the renderer, but you can still update the ",paraId:11,tocIndex:3},{value:"renderer",paraId:11,tocIndex:3},{value:" option through the ",paraId:11,tocIndex:3},{value:"setOptions",paraId:11,tocIndex:3},{value:" method.",paraId:11,tocIndex:3},{value:"import { Renderer as SVGRenderer } from '@antv/g-svg';\nimport { Renderer as WebGLRenderer } from '@antv/g-webgl';\n\n// Use the WebGL renderer by default\nconst graph = new Graph({\n  // ... other options\n  renderer: () => new WebGLRenderer(),\n});\n\nawait graph.render();\n\n// Switch to the SVG renderer\ngraph.setOptions({\n  renderer: () => new SVGRenderer(),\n});\n",paraId:12,tocIndex:3}]},5438:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(41065);const t=[{value:"# npm\nnpm install @antv/g6 --save\n\n# pnpm\npnpm add @antv/g6\n\n# yarn\nyarn add @antv/g6\n",paraId:0,tocIndex:0},{value:"Import G6 in the code:",paraId:1,tocIndex:0},{value:"import { Graph } from '@antv/g6';\n",paraId:2,tocIndex:0},{value:"Visit ",paraId:3,tocIndex:0},{value:"G6 npm Example",paraId:3,tocIndex:0},{value:" to view the complete example code.",paraId:3,tocIndex:0},{value:"@antv/g6",paraId:4,tocIndex:1},{value:" Available on multiple CDNs:",paraId:4,tocIndex:1},{value:"unpkg: ",paraId:5,tocIndex:1},{value:"https://unpkg.com/@antv/g6@5/dist/g6.min.js",paraId:5,tocIndex:1},{value:"jsDelivr: ",paraId:5,tocIndex:1},{value:"https://cdn.jsdelivr.net/npm/@antv/g6@5/dist/g6.min.js",paraId:5,tocIndex:1},{value:"npmmirror: ",paraId:5,tocIndex:1},{value:"https://registry.npmmirror.com/@antv/g6/5/files/dist/g6.min.js",paraId:5,tocIndex:1},{value:"Import G6 using a ",paraId:6,tocIndex:1},{value:"script",paraId:6,tocIndex:1},{value:" tag:",paraId:6,tocIndex:1},{value:'<script src="https://unpkg.com/@antv/g6@5/dist/g6.min.js"><\/script>\n',paraId:7,tocIndex:1},{value:"Visit ",paraId:8,tocIndex:1},{value:"G6 CDN Example",paraId:8,tocIndex:1},{value:" to view the complete example code.",paraId:8,tocIndex:1}]},45804:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(4317);const t=[{value:"Refer to the example below, you can use G6 in Angular, and you can also view the ",paraId:0},{value:"Live Example",paraId:0},{value:"。",paraId:0},{value:"app.component.html",paraId:1},{value:"<div>\n  <h1>{{ title }}</h1>\n  <div #container></div>\n</div>\n",paraId:2},{value:"app.component.ts",paraId:3},{value:"import { Component, ViewChild, ElementRef } from '@angular/core';\nimport { Graph } from '@antv/g6';\n\n@Component({\n  selector: 'app-root',\n  templateUrl: './app.component.html',\n  styleUrls: ['./app.component.css'],\n})\nexport class AppComponent {\n  title = 'Use G6 in Angular';\n\n  @ViewChild('container') container: ElementRef;\n\n  ngAfterViewInit() {\n    const graph = new Graph({\n      container: this.container.nativeElement,\n      width: 500,\n      height: 500,\n      data: {\n        nodes: [\n          {\n            id: 'node-1',\n            style: { x: 50, y: 100 },\n          },\n          {\n            id: 'node-2',\n            style: { x: 150, y: 100 },\n          },\n        ],\n        edges: [{ id: 'edge-1', source: 'node-1', target: 'node-2' }],\n      },\n    });\n\n    graph.render();\n  }\n}\n",paraId:4}]},11978:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(11915);const t=[{value:"Refer to the example below, you can use G6 in React, and you can also view the ",paraId:0,tocIndex:0},{value:"Live Example",paraId:0,tocIndex:0},{value:" 。",paraId:0,tocIndex:0},{value:"import { Graph } from '@antv/g6';\nimport { useEffect, useRef } from 'react';\n\nexport default () => {\n  const containerRef = useRef<HTMLDivElement>(null);\n\n  useEffect(() => {\n    const graph = new Graph({\n      container: containerRef.current!,\n      width: 500,\n      height: 500,\n      data: {\n        nodes: [\n          {\n            id: 'node-1',\n            style: { x: 50, y: 100 },\n          },\n          {\n            id: 'node-2',\n            style: { x: 150, y: 100 },\n          },\n        ],\n        edges: [{ id: 'edge-1', source: 'node-1', target: 'node-2' }],\n      },\n    });\n\n    graph.render();\n  }, []);\n\n  return <div ref={containerRef} />;\n};\n",paraId:1,tocIndex:0},{value:"In strict mode, React will update twice, causing G6 to create and destroy the Graph instance repeatedly. You can refer to the following example to solve this problem:",paraId:2,tocIndex:1},{value:"import type { GraphOptions } from '@antv/g6';\nimport { Graph as G6Graph } from '@antv/g6';\nimport { useEffect, useRef } from 'react';\n\nexport interface GraphProps {\n  options: GraphOptions;\n  onRender?: (graph: G6Graph) => void;\n  onDestroy?: () => void;\n}\n\nexport const Graph = (props: GraphProps) => {\n  const { options, onRender, onDestroy } = props;\n  const graphRef = useRef<G6Graph>();\n  const containerRef = useRef<HTMLDivElement>(null);\n\n  useEffect(() => {\n    const graph = new G6Graph({ container: containerRef.current! });\n    graphRef.current = graph;\n\n    return () => {\n      const graph = graphRef.current;\n      if (graph) {\n        graph.destroy();\n        onDestroy?.();\n        graphRef.current = undefined;\n      }\n    };\n  }, []);\n\n  useEffect(() => {\n    const container = containerRef.current;\n    const graph = graphRef.current;\n\n    if (!options || !container || !graph || graph.destroyed) return;\n\n    graph.setOptions(options);\n    graph\n      .render()\n      .then(() => onRender?.(graph))\n      // eslint-disable-next-line no-console\n      .catch((error) => console.debug(error));\n  }, [options]);\n\n  return <div ref={containerRef} style={{ width: '100%', height: '100%' }} />;\n};\n",paraId:3,tocIndex:1}]},20338:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(12996);const t=[{value:"Please do not pass Vue reactive data directly to the G6 instance, which may cause G6 to fail to render correctly, or even cause the page to crash.",paraId:0},{value:"Refer to the example below, you can use G6 in Vue, and you can also view the ",paraId:1},{value:"Live Example",paraId:1},{value:"。",paraId:1},{value:"<template>\n  <div id=\"container\"></div>\n</template>\n\n<script setup>\n  import { onMounted } from 'vue';\n  import { Graph } from '@antv/g6';\n\n  onMounted(() => {\n    const graph = new Graph({\n      container: document.getElementById('container'),\n      width: 500,\n      height: 500,\n      data: {\n        nodes: [\n          {\n            id: 'node-1',\n            style: { x: 50, y: 100 },\n          },\n          {\n            id: 'node-2',\n            style: { x: 150, y: 100 },\n          },\n        ],\n        edges: [{ id: 'edge-1', source: 'node-1', target: 'node-2' }],\n      },\n    });\n\n    graph.render();\n  });\n<\/script>\n",paraId:2}]},75195:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(44425);const t=[{value:"Visit ",paraId:0,tocIndex:0},{value:"Chart Examples",paraId:1,tocIndex:0},{value:" to experience G6 online without any environment setup.",paraId:0,tocIndex:0},{value:"In this example, we will create a simple graph using G6 based on an HTML page.",paraId:2,tocIndex:1},{value:"Copy the following code into an HTML file and then open this file in a browser:",paraId:3,tocIndex:1},{value:"\x3c!-- Prepare a container --\x3e\n<div id=\"container\" style=\"width: 500px; height: 500px\"></div>\n\n\x3c!-- Import G6's JS file --\x3e\n<script src=\"https://unpkg.com/@antv/g6@5/dist/g6.min.js\"><\/script>\n\n<script>\n  const { Graph } = G6;\n\n  fetch('https://assets.antv.antgroup.com/g6/graph.json')\n    .then((res) => res.json())\n    .then((data) => {\n      const graph = new Graph({\n        container: 'container',\n        autoFit: 'view',\n        data,\n        node: {\n          style: {\n            size: 10,\n          },\n          palette: {\n            field: 'group',\n            color: 'tableau',\n          },\n        },\n        layout: {\n          type: 'd3-force',\n          manyBody: {},\n          x: {},\n          y: {},\n        },\n        behaviors: ['drag-canvas', 'zoom-canvas', 'drag-element'],\n      });\n\n      graph.render();\n    });\n<\/script>\n",paraId:4,tocIndex:1},{value:"You will get a graph as shown below:",paraId:5,tocIndex:1},{value:"fetch('https://assets.antv.antgroup.com/g6/graph.json')\n  .then((res) => res.json())\n  .then((data) =>\n    createGraph(\n      {\n        data,\n        autoFit: 'view',\n        animation: false,\n        node: {\n          style: {\n            size: 10,\n          },\n          palette: {\n            field: 'group',\n            color: 'tableau',\n          },\n        },\n        layout: {\n          type: 'd3-force',\n          animation: false,\n          manyBody: {},\n          x: {},\n          y: {},\n        },\n        behaviors: ['drag-canvas', 'zoom-canvas', 'drag-element'],\n      },\n      { width: 500, height: 500 },\n    ),\n  );\n",paraId:6,tocIndex:1},{value:"Let's analyze the following code snippet:",paraId:7,tocIndex:1},{value:"First, we create a ",paraId:8,tocIndex:1},{value:"div",paraId:8,tocIndex:1},{value:" element to serve as the container for the graph:",paraId:8,tocIndex:1},{value:'<div id="container" style="width: 500px; height: 500px"></div>\n',paraId:9,tocIndex:1},{value:"Then, include the G6's JS file:",paraId:10,tocIndex:1},{value:'<script src="https://unpkg.com/@antv/g6@5/dist/g6.min.js"><\/script>\n',paraId:11,tocIndex:1},{value:"Use the ",paraId:12,tocIndex:1},{value:"fetch",paraId:12,tocIndex:1},{value:" method to obtain the graph's data:",paraId:12,tocIndex:1},{value:"fetch('https://assets.antv.antgroup.com/g6/graph.json').then((res) => res.json());\n",paraId:13,tocIndex:1},{value:"Finally, create an instance of the graph, pass in the configuration object, and call the ",paraId:14,tocIndex:1},{value:"render",paraId:14,tocIndex:1},{value:" method to render the graph:",paraId:14,tocIndex:1},{value:"const { Graph } = G6;\n\nconst graph = new Graph({\n  container: 'container',\n  autoFit: 'view',\n  data,\n  node: {\n    style: {\n      size: 10,\n    },\n    palette: {\n      field: 'group',\n      color: 'tableau',\n    },\n  },\n  layout: {\n    type: 'd3-force',\n    manyBody: {},\n    x: {},\n    y: {},\n  },\n  behaviors: ['drag-canvas', 'zoom-canvas', 'drag-element'],\n});\n\ngraph.render();\n",paraId:15,tocIndex:1},{value:"If you are using frameworks such as React, Vue, Angular, etc., you can refer to:",paraId:16,tocIndex:1},{value:"Using G6 in React",paraId:17,tocIndex:1},{value:"Using G6 in Vue",paraId:18,tocIndex:1},{value:"Using G6 in Angular",paraId:19,tocIndex:1}]},46258:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(70375);const t=[{value:"This tutorial will guide you through the development of a G6 chart from scratch, and along the way, you will learn and understand the main concepts of G6.",paraId:0},{value:"We will use Vite to create a simple front-end application.",paraId:1,tocIndex:0},{value:"First, create an empty directory:",paraId:2,tocIndex:1},{value:"mkdir g6-tutorial\n\ncd g6-tutorial\n",paraId:3,tocIndex:1},{value:"Initialize the project:",paraId:4,tocIndex:1},{value:"npm init -y\n",paraId:5,tocIndex:1},{value:"Install G6:",paraId:6,tocIndex:1},{value:"npm install @antv/g6 --save\n",paraId:7,tocIndex:1},{value:"Vite is a new type of front-end build tool that is based on ESModule and can quickly start up projects.",paraId:8,tocIndex:1},{value:"Install Vite:",paraId:9,tocIndex:1},{value:"npm install vite --save-dev\n",paraId:10,tocIndex:1},{value:"Add a start script to the ",paraId:11,tocIndex:1},{value:"package.json",paraId:11,tocIndex:1},{value:":",paraId:11,tocIndex:1},{value:'{\n  "scripts": {\n    "dev": "vite"\n  }\n}\n',paraId:12,tocIndex:1},{value:"Create the ",paraId:13,tocIndex:2},{value:"index.html",paraId:13,tocIndex:2},{value:" and ",paraId:13,tocIndex:2},{value:"main.ts",paraId:13,tocIndex:2},{value:" files with the following content:",paraId:13,tocIndex:2},{value:"index.html",paraId:14,tocIndex:2},{value:":",paraId:14,tocIndex:2},{value:'<!doctype html>\n<html>\n  <head>\n    <title>@antv/g6 Tutorial</title>\n  </head>\n  <body>\n    <div id="container"></div>\n    <script type="module" src="main.ts"><\/script>\n  </body>\n</html>\n',paraId:15,tocIndex:2},{value:"main.ts",paraId:16,tocIndex:2},{value:"：",paraId:16,tocIndex:2},{value:"alert('Hello, G6!');\n",paraId:17,tocIndex:2},{value:"npm run dev\n",paraId:18,tocIndex:3},{value:"Open a web browser and visit the address output in the terminal (typically: ",paraId:19,tocIndex:3},{value:"http://127.0.0.1:5173/",paraId:19,tocIndex:3},{value:'), and you will see a pop-up displaying "Hello, G6!".',paraId:19,tocIndex:3},{value:"Next, we will create a simple chart using G6.",paraId:20,tocIndex:4},{value:"G6 uses JSON-formatted data to describe the graph, which usually includes nodes and edges. We will use the following prepared data:",paraId:21,tocIndex:5},{value:"const data = {\n  nodes: [\n    { id: 'node-1', style: { x: 50, y: 50 } },\n    { id: 'node-2', style: { x: 150, y: 50 } },\n  ],\n  edges: [{ source: 'node-1', target: 'node-2' }],\n};\n",paraId:22,tocIndex:5},{value:"The data includes two nodes and one edge. The ",paraId:23,tocIndex:5},{value:"id",paraId:23,tocIndex:5},{value:" attribute for nodes is mandatory, and the position of each node is set in the ",paraId:23,tocIndex:5},{value:"style",paraId:23,tocIndex:5},{value:". The ",paraId:23,tocIndex:5},{value:"source",paraId:23,tocIndex:5},{value:" and ",paraId:23,tocIndex:5},{value:"target",paraId:23,tocIndex:5},{value:" attributes of the edge represent the ",paraId:23,tocIndex:5},{value:"id",paraId:23,tocIndex:5},{value:" of the starting node and the ending node, respectively.",paraId:23,tocIndex:5},{value:"Create an instance of the Graph, pass in a configuration object that includes the container and data, and then call the ",paraId:24,tocIndex:6},{value:"render",paraId:24,tocIndex:6},{value:" method to draw the Graph:",paraId:24,tocIndex:6},{value:"import { Graph } from '@antv/g6';\n\nconst graph = new Graph({\n  container: 'container',\n  data: {\n    nodes: [\n      { id: 'node-1', style: { x: 50, y: 50 } },\n      { id: 'node-2', style: { x: 150, y: 50 } },\n    ],\n    edges: [{ source: 'node-1', target: 'node-2' }],\n  },\n});\n\ngraph.render();\n",paraId:25,tocIndex:6},{value:"As shown below, you can see that the chart has been successfully drawn:",paraId:26,tocIndex:6},{value:"createGraph(\n  {\n    data: {\n      nodes: [\n        { id: 'node-1', style: { x: 50, y: 50 } },\n        { id: 'node-2', style: { x: 150, y: 50 } },\n      ],\n      edges: [{ source: 'node-1', target: 'node-2' }],\n    },\n  },\n  { width: 200, height: 100 },\n);\n",paraId:27,tocIndex:6},{value:"Next, we will introduce how to configure the style and types of elements in the canvas.",paraId:28,tocIndex:7},{value:"G6 provides various mechanisms to configure element styles, which can be done in the data itself or within the chart instance. In the previous example, we configured the position of the nodes in the data. Next, we will configure the styles of nodes and edges in the graph configuration options:",paraId:29,tocIndex:7},{value:"import { Graph } from '@antv/g6';\n\nconst graph = new Graph({\n  container: 'container',\n  data: {\n    nodes: [\n      { id: 'node-1', style: { x: 50, y: 50 } },\n      { id: 'node-2', style: { x: 150, y: 50 } },\n    ],\n    edges: [{ source: 'node-1', target: 'node-2' }],\n  },\n  node: {\n    style: {\n      fill: 'pink',\n    },\n  },\n  edge: {\n    style: {\n      stroke: 'lightgreen',\n    },\n  },\n});\n\ngraph.render();\n",paraId:30,tocIndex:7},{value:"As the code shows, we have configured the fill color of the nodes to be pink and the stroke color of the edges to be light green within the chart instance. You can see the effect in the example below:",paraId:31,tocIndex:7},{value:"createGraph(\n  {\n    data: {\n      nodes: [\n        { id: 'node-1', style: { x: 50, y: 50 } },\n        { id: 'node-2', style: { x: 150, y: 50 } },\n      ],\n      edges: [{ source: 'node-1', target: 'node-2' }],\n    },\n    node: {\n      style: {\n        fill: 'pink',\n      },\n    },\n    edge: {\n      style: {\n        stroke: 'lightgreen',\n      },\n    },\n  },\n  { width: 200, height: 100 },\n);\n",paraId:32,tocIndex:7},{value:"The key parts are the ",paraId:33,tocIndex:7},{value:"node.style",paraId:33,tocIndex:7},{value:" and ",paraId:33,tocIndex:7},{value:"edge.style",paraId:33,tocIndex:7},{value:" options, which are used to configure the styles of nodes and edges, respectively.",paraId:33,tocIndex:7},{value:"In the subsequent code examples, we will only display the parts of the options. For the complete code of this project, please refer to the ",paraId:34,tocIndex:7},{value:"Complete Example",paraId:34,tocIndex:7},{value:".",paraId:34,tocIndex:7},{value:"Next, we will demonstrate more types of nodes by setting the node type:",paraId:35,tocIndex:7},{value:"{\n  node: {\n    type: (datum) => datum.id === 'node-1' ? 'circle' : 'rect',\n    style: {\n      fill: 'pink',\n      size: 20\n    }\n  }\n}\n",paraId:36,tocIndex:7},{value:"In the code above, we set the ",paraId:37,tocIndex:7},{value:"type",paraId:37,tocIndex:7},{value:" attribute of the node, which can be a string or a function. When ",paraId:37,tocIndex:7},{value:"type",paraId:37,tocIndex:7},{value:" is a function, the argument of the function is the current node's data object, and the return value is the type of the node.",paraId:37,tocIndex:7},{value:"Similarly, each attribute under the ",paraId:38,tocIndex:7},{value:"style",paraId:38,tocIndex:7},{value:" style of an element can also be a function, with the argument being the current element's data object.",paraId:38,tocIndex:7},{value:"You can even set the entire ",paraId:39,tocIndex:7},{value:"style",paraId:39,tocIndex:7},{value:" property as a function, allowing you to dynamically set the element's style based on the data object.",paraId:39,tocIndex:7},{value:"The circular node (",paraId:40,tocIndex:7},{value:"circle",paraId:40,tocIndex:7},{value:") is the default node type in G6. Here, we set the type of the first node to a circle and the type of the second node to a rectangle.",paraId:40,tocIndex:7},{value:"At the same time, we also set the size of the nodes to 20, so the first node is a circle with a radius of 10, and the second node is a square with a side length of 20.",paraId:41,tocIndex:7},{value:"If you want to set the size of the rectangular node to 20x10, you can set ",paraId:42,tocIndex:7},{value:"size",paraId:42,tocIndex:7},{value:" to an array ",paraId:42,tocIndex:7},{value:"[20, 10]",paraId:42,tocIndex:7},{value:".",paraId:42,tocIndex:7},{value:"You can see the effect in the example below:",paraId:43,tocIndex:7},{value:"createGraph(\n  {\n    data: {\n      nodes: [\n        { id: 'node-1', style: { x: 50, y: 50 } },\n        { id: 'node-2', style: { x: 150, y: 50 } },\n      ],\n      edges: [{ source: 'node-1', target: 'node-2' }],\n    },\n    node: {\n      type: (datum) => (datum.id === 'node-1' ? 'circle' : 'rect'),\n      style: {\n        fill: 'pink',\n        size: 20,\n      },\n    },\n    edge: {\n      style: {\n        stroke: 'lightgreen',\n      },\n    },\n  },\n  { width: 200, height: 100 },\n);\n",paraId:44,tocIndex:7},{value:"The chart provided in the previous example is static. Next, we will add some interactive behaviors.",paraId:45,tocIndex:8},{value:"G6 offers a variety of interactive behaviors. We will add a few commonly used Behaviors to allow users to drag, zoom the canvas, and drag nodes.",paraId:46,tocIndex:8},{value:"{\n  behaviors: ['drag-canvas', 'zoom-canvas', 'drag-element'];\n}\n",paraId:47,tocIndex:8},{value:"Try dragging nodes and the canvas in the example below, and use the scroll wheel to zoom in and out on the canvas:",paraId:48,tocIndex:8},{value:"createGraph(\n  {\n    data: {\n      nodes: [\n        { id: 'node-1', style: { x: 50, y: 50 } },\n        { id: 'node-2', style: { x: 150, y: 50 } },\n      ],\n      edges: [{ source: 'node-1', target: 'node-2' }],\n    },\n    node: {\n      type: (datum) => (datum.id === 'node-1' ? 'circle' : 'rect'),\n      style: {\n        fill: 'pink',\n        size: 20,\n      },\n    },\n    edge: {\n      style: {\n        stroke: 'lightgreen',\n      },\n    },\n    behaviors: ['drag-canvas', 'zoom-canvas', 'drag-element'],\n  },\n  { width: 300, height: 200 },\n);\n",paraId:49,tocIndex:8},{value:"In the previous example, we manually set the positions of the nodes. However, this can become very difficult when there are many nodes.",paraId:50,tocIndex:9},{value:"Layout algorithms can automatically adjust the positions of nodes based on certain rules. G6 provides a variety of layout algorithms, such as tree layout, force-directed layout, and so on.",paraId:51,tocIndex:9},{value:"First, generate a set of data that does not include position information:",paraId:52,tocIndex:9},{value:"const data = {\n  nodes: Array.from({ length: 10 }).map((_, i) => ({ id: `node-${i}` })),\n  edges: Array.from({ length: 9 }).map((_, i) => ({ source: `node-0`, target: `node-${i + 1}` })),\n};\n",paraId:53,tocIndex:9},{value:"By default, if a node does not have position information, G6 will place the node at the top-left corner, that is, at the coordinates ",paraId:54,tocIndex:9},{value:"(0, 0)",paraId:54,tocIndex:9},{value:".",paraId:54,tocIndex:9},{value:"Next, we will use the ",paraId:55,tocIndex:9},{value:"d3-force",paraId:55,tocIndex:9},{value:" layout algorithm, which is a force-directed layout algorithm that can simulate the forces of attraction and repulsion between nodes, allowing the nodes to automatically adjust to suitable positions.",paraId:55,tocIndex:9},{value:"{\n  layout: {\n    type: 'd3-force',\n  },\n}\n",paraId:56,tocIndex:9},{value:"View the example below, and you can see that the nodes have automatically adjusted to suitable positions:",paraId:57,tocIndex:9},{value:"Complete Code",paraId:58},{value:"import { Graph } from '@antv/g6';\n\nconst graph = new Graph({\n  container: 'container',\n  data: {\n    nodes: Array.from({ length: 10 }).map((_, i) => ({ id: `node-${i}` })),\n    edges: Array.from({ length: 9 }).map((_, i) => ({ source: `node-0`, target: `node-${i + 1}` })),\n  },\n  node: {\n    style: {\n      size: 20,\n      fill: 'pink',\n    },\n  },\n  edge: {\n    style: {\n      stroke: 'lightgreen',\n    },\n  },\n  behaviors: ['drag-canvas', 'zoom-canvas', 'drag-element'],\n  layout: {\n    type: 'd3-force',\n  },\n});\n\ngraph.render();\n",paraId:59,tocIndex:9},{value:"createGraph(\n  {\n    data: {\n      nodes: Array.from({ length: 10 }).map((_, i) => ({ id: `node-${i}` })),\n      edges: Array.from({ length: 9 }).map((_, i) => ({ source: `node-0`, target: `node-${i + 1}` })),\n    },\n    node: {\n      style: {\n        size: 20,\n        fill: 'pink',\n      },\n    },\n    edge: {\n      style: {\n        stroke: 'lightgreen',\n      },\n    },\n    behaviors: ['drag-canvas', 'zoom-canvas', 'drag-element'],\n    layout: {\n      type: 'd3-force',\n    },\n  },\n  { width: 200, height: 200 },\n);\n",paraId:60,tocIndex:9},{value:"Similarly, when there are many nodes, manually setting the color of each node can become difficult. G6 provides a palette mechanism that makes it easy to assign colors to elements.",paraId:61,tocIndex:10},{value:"Palettes typically assign colors to elements based on a specific field in the data, such as the type of node, the weight of an edge, etc.",paraId:62,tocIndex:10},{value:"Below, we add a ",paraId:63,tocIndex:10},{value:"category",paraId:63,tocIndex:10},{value:" field in the data:",paraId:63,tocIndex:10},{value:"const data = {\n  nodes: Array.from({ length: 10 }).map((_, i) => ({\n    id: `node-${i}`,\n    data: { category: i === 0 ? 'central' : 'around' },\n  })),\n  edges: Array.from({ length: 9 }).map((_, i) => ({ source: `node-0`, target: `node-${i + 1}` })),\n};\n",paraId:64,tocIndex:10},{value:"Then, use the ",paraId:65,tocIndex:10},{value:"tableau",paraId:65,tocIndex:10},{value:" palette to set the colors for the nodes, where the ",paraId:65,tocIndex:10},{value:"field",paraId:65,tocIndex:10},{value:" attribute specifies the field in the data, and the ",paraId:65,tocIndex:10},{value:"color",paraId:65,tocIndex:10},{value:" attribute specifies the name of the palette.",paraId:65,tocIndex:10},{value:"{\n  node: {\n    palette: {\n      field: 'category',\n      color: 'tableau',\n    }\n  }\n}\n",paraId:66,tocIndex:10},{value:"It is important to note that the ",paraId:67,tocIndex:10},{value:"fill",paraId:67,tocIndex:10},{value:" style in ",paraId:67,tocIndex:10},{value:"node.style",paraId:67,tocIndex:10},{value:" should be removed, as its priority is higher than the colors assigned by the palette.",paraId:67,tocIndex:10},{value:"createGraph(\n  {\n    data: {\n      nodes: Array.from({ length: 10 }).map((_, i) => ({\n        id: `node-${i}`,\n        data: { category: i === 0 ? 'central' : 'around' },\n      })),\n      edges: Array.from({ length: 9 }).map((_, i) => ({ source: `node-0`, target: `node-${i + 1}` })),\n    },\n    node: {\n      style: {\n        size: 20,\n      },\n      palette: {\n        field: 'category',\n        color: 'tableau',\n      },\n    },\n    edge: {\n      style: {\n        stroke: 'lightgreen',\n      },\n    },\n    behaviors: ['drag-canvas', 'zoom-canvas', 'drag-element'],\n    layout: {\n      type: 'd3-force',\n    },\n  },\n  { width: 200, height: 200 },\n);\n",paraId:68,tocIndex:10},{value:"The plugin mechanism is an important feature of G6, which allows you to extend the functionality of G6 through plugins. G6 provides a wealth of built-in plugins, such as ",paraId:69,tocIndex:11},{value:"tooltip",paraId:69,tocIndex:11},{value:", ",paraId:69,tocIndex:11},{value:"legend",paraId:69,tocIndex:11},{value:", etc., and also supports user-defined plugins.",paraId:69,tocIndex:11},{value:"Below, we will use the ",paraId:70,tocIndex:11},{value:"grid-line",paraId:70,tocIndex:11},{value:" plugin to add grid lines to the canvas:",paraId:70,tocIndex:11},{value:"{\n  plugins: ['grid-line'],\n}\n",paraId:71,tocIndex:11},{value:"You can see that grid lines have been added to the canvas:",paraId:72,tocIndex:11},{value:"createGraph(\n  {\n    data: {\n      nodes: Array.from({ length: 10 }).map((_, i) => ({\n        id: `node-${i}`,\n        data: { category: i === 0 ? 'central' : 'around' },\n      })),\n      edges: Array.from({ length: 9 }).map((_, i) => ({ source: `node-0`, target: `node-${i + 1}` })),\n    },\n    node: {\n      style: {\n        size: 20,\n      },\n      palette: {\n        field: 'category',\n        color: 'tableau',\n      },\n    },\n    edge: {\n      style: {\n        stroke: 'lightgreen',\n      },\n    },\n    behaviors: ['drag-canvas', 'zoom-canvas', 'drag-element'],\n    layout: {\n      type: 'd3-force',\n    },\n    plugins: ['grid-line'],\n  },\n  { width: 200, height: 200 },\n);\n",paraId:73,tocIndex:11},{value:"The plugin configuration mentioned above used a shorthand form. Most plugins support the passing of additional parameters. For example, the ",paraId:74,tocIndex:11},{value:"grid-line",paraId:74,tocIndex:11},{value:" plugin allows you to configure the ",paraId:74,tocIndex:11},{value:"follow",paraId:74,tocIndex:11},{value:" property to specify whether the grid lines should follow the canvas when it is dragged.",paraId:74,tocIndex:11},{value:"{\n  plugins: [{ type: 'grid-line', follow: true }];\n}\n",paraId:75,tocIndex:11},{value:"Try dragging the canvas in the example below, and you will see that the grid lines move along with the canvas:",paraId:76,tocIndex:11},{value:"createGraph(\n  {\n    data: {\n      nodes: Array.from({ length: 10 }).map((_, i) => ({\n        id: `node-${i}`,\n        data: { category: i === 0 ? 'central' : 'around' },\n      })),\n      edges: Array.from({ length: 9 }).map((_, i) => ({ source: `node-0`, target: `node-${i + 1}` })),\n    },\n    node: {\n      style: {\n        size: 20,\n      },\n      palette: {\n        field: 'category',\n        color: 'tableau',\n      },\n    },\n    edge: {\n      style: {\n        stroke: 'lightgreen',\n      },\n    },\n    behaviors: ['drag-canvas', 'zoom-canvas', 'drag-element'],\n    layout: {\n      type: 'd3-force',\n    },\n    plugins: [{ type: 'grid-line', follow: true }],\n  },\n  { width: 200, height: 200 },\n);\n",paraId:77,tocIndex:11},{value:"In this tutorial, we created a G6 chart from scratch and became acquainted with the main concepts of G6. We learned how to create a simple chart, how to configure the style and types of elements, how to add interactive behaviors, how to use layout algorithms, how to use palettes, and how to use plugins.",paraId:78,tocIndex:12},{value:"For a more detailed introduction to the concepts of G6, you can refer to ",paraId:79,tocIndex:12},{value:"Core Concepts",paraId:80,tocIndex:12},{value:".",paraId:79,tocIndex:12},{value:"Detailed explanations of options such as elements, layouts, and plugins can be found in the ",paraId:81,tocIndex:12},{value:"API",paraId:82,tocIndex:12},{value:".",paraId:81,tocIndex:12}]},66367:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(74848);const t=[{value:"Extension is an important concept in G6, it is a general term for all expandable parts in G6, including the following types:",paraId:0,tocIndex:0},{value:"Animation",paraId:1,tocIndex:0},{value:"Behavior",paraId:1,tocIndex:0},{value:"Element\n",paraId:1,tocIndex:0},{value:"Node",paraId:2,tocIndex:0},{value:"Edge",paraId:2,tocIndex:0},{value:"Combo",paraId:2,tocIndex:0},{value:"Layout",paraId:1,tocIndex:0},{value:"Palette",paraId:1,tocIndex:0},{value:"Plugin",paraId:1,tocIndex:0},{value:"Theme",paraId:1,tocIndex:0},{value:"Transform",paraId:1,tocIndex:0},{value:"G6 provides the ",paraId:3,tocIndex:1},{value:"register",paraId:3,tocIndex:1},{value:" function for registering extensions, for example:",paraId:3,tocIndex:1},{value:"import { register, ExtensionCategory } from '@antv/g6';\nimport { CustomNode } from './my-custom-node';\n\n// # Registering Nodes\nregister(ExtensionCategory.NODE, 'custom-node', CustomNode);\n",paraId:4,tocIndex:1},{value:"The first parameter of the ",paraId:5,tocIndex:1},{value:"register",paraId:5,tocIndex:1},{value:" function is the type of the extension, the second parameter is the name of the extension, and the third parameter is the implementation of the extension.",paraId:5,tocIndex:1},{value:"Different types of extensions ",paraId:6,tocIndex:1},{value:"can",paraId:6,tocIndex:1},{value:" use the same extension name, but when registering extensions of the same type, only the first registration will take effect.",paraId:6,tocIndex:1},{value:"For detailed parameter signatures, see: ",paraId:7,tocIndex:1},{value:"API Documentation",paraId:8,tocIndex:1},{value:"// ✅\nregister(ExtensionCategory.NODE, 'custom-name', CustomNode);\nregister(ExtensionCategory.COMBO, 'custom-name', CustomCombo);\n\n// ❌\nregister(ExtensionCategory.NODE, 'custom-name', CustomNode);\nregister(ExtensionCategory.NODE, 'custom-name', CustomNode);\n",paraId:9,tocIndex:1},{value:"The configuration location for different types of extensions varies, but all are used by specifying the name that was used during registration, for example:",paraId:10,tocIndex:2},{value:"Using node extensions: ",paraId:11,tocIndex:2},{value:"options.node.type",paraId:11,tocIndex:2},{value:"Using edge extensions: ",paraId:11,tocIndex:2},{value:"options.edge.type",paraId:11,tocIndex:2},{value:"Using combo extensions: ",paraId:11,tocIndex:2},{value:"options.combo.type",paraId:11,tocIndex:2},{value:"Using behavior extensions: ",paraId:11,tocIndex:2},{value:"options.behaviors",paraId:11,tocIndex:2},{value:"Using layout extensions: ",paraId:11,tocIndex:2},{value:"options.layout.type",paraId:11,tocIndex:2},{value:"Using plugin extensions: ",paraId:11,tocIndex:2},{value:"options.plugins",paraId:11,tocIndex:2},{value:"Using theme extensions: ",paraId:11,tocIndex:2},{value:"options.theme",paraId:11,tocIndex:2},{value:"Using data transform extensions: ",paraId:11,tocIndex:2},{value:"options.transform",paraId:11,tocIndex:2},{value:"Using palette extensions: ",paraId:11,tocIndex:2},{value:"options.node.palette",paraId:11,tocIndex:2},{value:", ",paraId:11,tocIndex:2},{value:"options.edge.palette",paraId:11,tocIndex:2},{value:", etc.",paraId:11,tocIndex:2},{value:"Using animation extensions: ",paraId:11,tocIndex:2},{value:"options.node.animate",paraId:11,tocIndex:2},{value:", ",paraId:11,tocIndex:2},{value:"options.edge.animate",paraId:11,tocIndex:2},{value:", etc.",paraId:11,tocIndex:2},{value:"G6 provides the ",paraId:12,tocIndex:3},{value:"getExtension",paraId:12,tocIndex:3},{value:" and ",paraId:12,tocIndex:3},{value:"getExtensions",paraId:12,tocIndex:3},{value:" methods to obtain a single extension and all extensions of a specified type, respectively, for example:",paraId:12,tocIndex:3},{value:"import { getExtension, getExtensions, ExtensionCategory } from '@antv/g6';\n\n// To get the implementation of the node extension registered with the name 'custom-node'\ngetExtension(ExtensionCategory.NODE, 'custom-node');\n\n// Retrieve all registered node extension implementations\ngetExtensions(ExtensionCategory.NODE);\n",paraId:13,tocIndex:3}]},94435:function(e,a,n){n.r(a),n.d(a,{texts:function(){return t}});n(94259);const t=[{value:"title: Built-in Extensions\norder: 4",paraId:0},{value:"The G6 built-in extensions and registered types are as follows:",paraId:1},{value:"Extension",paraId:2,tocIndex:0},{value:"Registration Type",paraId:2,tocIndex:0},{value:"ComboCollapse",paraId:2,tocIndex:0},{value:"'combo-collapse'",paraId:2,tocIndex:0},{value:"ComboExpand",paraId:2,tocIndex:0},{value:"'combo-expand'",paraId:2,tocIndex:0},{value:"NodeCollapse",paraId:2,tocIndex:0},{value:"'node-collapse'",paraId:2,tocIndex:0},{value:"NodeExpand",paraId:2,tocIndex:0},{value:"'node-expand'",paraId:2,tocIndex:0},{value:"PathIn",paraId:2,tocIndex:0},{value:"'path-in'",paraId:2,tocIndex:0},{value:"PathOut",paraId:2,tocIndex:0},{value:"'path-out'",paraId:2,tocIndex:0},{value:"Fade",paraId:2,tocIndex:0},{value:"'fade'",paraId:2,tocIndex:0},{value:"Translate",paraId:2,tocIndex:0},{value:"'translate'",paraId:2,tocIndex:0},{value:"Usage:",paraId:3,tocIndex:0},{value:"In ",paraId:4,tocIndex:0},{value:"GraphOptions.[node|edge|combo].animation.[stage]",paraId:4,tocIndex:0},{value:", for example:",paraId:4,tocIndex:0},{value:"const graph = new Graph({\n  // ... other options\n  node: {\n    animation: {\n      update: 'translate', // Only use translation animation in the update stage\n    },\n  },\n});\n",paraId:5,tocIndex:0},{value:"Extension",paraId:6,tocIndex:1},{value:"Registration Type",paraId:6,tocIndex:1},{value:"Description",paraId:6,tocIndex:1},{value:"BrushSelect",paraId:6,tocIndex:1},{value:"'brush-select'",paraId:6,tocIndex:1},{value:"/",paraId:6,tocIndex:1},{value:"ClickSelect",paraId:6,tocIndex:1},{value:"'click-select'",paraId:6,tocIndex:1},{value:"/",paraId:6,tocIndex:1},{value:"CollapseExpand",paraId:6,tocIndex:1},{value:"'collapse-expand'",paraId:6,tocIndex:1},{value:"/",paraId:6,tocIndex:1},{value:"CreateEdge",paraId:6,tocIndex:1},{value:"'create-edge'",paraId:6,tocIndex:1},{value:"/",paraId:6,tocIndex:1},{value:"DragCanvas",paraId:6,tocIndex:1},{value:"'drag-canvas'",paraId:6,tocIndex:1},{value:"/",paraId:6,tocIndex:1},{value:"DragElementForce",paraId:6,tocIndex:1},{value:"'drag-element-force'",paraId:6,tocIndex:1},{value:"Drag element when use d3-force layout",paraId:6,tocIndex:1},{value:"DragElement",paraId:6,tocIndex:1},{value:"'drag-element'",paraId:6,tocIndex:1},{value:"/",paraId:6,tocIndex:1},{value:"FixElementSize",paraId:6,tocIndex:1},{value:"'fix-element-size'",paraId:6,tocIndex:1},{value:"Keep the size of element during zooming canvas",paraId:6,tocIndex:1},{value:"FocusElement",paraId:6,tocIndex:1},{value:"'focus-element'",paraId:6,tocIndex:1},{value:"/",paraId:6,tocIndex:1},{value:"HoverActivate",paraId:6,tocIndex:1},{value:"'hover-activate'",paraId:6,tocIndex:1},{value:"/",paraId:6,tocIndex:1},{value:"LassoSelect",paraId:6,tocIndex:1},{value:"'lasso-select'",paraId:6,tocIndex:1},{value:"/",paraId:6,tocIndex:1},{value:"OptimizeViewportTransform",paraId:6,tocIndex:1},{value:"'optimize-viewport-transform'",paraId:6,tocIndex:1},{value:"Hide elements during manipulate the canvas",paraId:6,tocIndex:1},{value:"ScrollCanvas",paraId:6,tocIndex:1},{value:"'scroll-canvas'",paraId:6,tocIndex:1},{value:"/",paraId:6,tocIndex:1},{value:"ZoomCanvas",paraId:6,tocIndex:1},{value:"'zoom-canvas'",paraId:6,tocIndex:1},{value:"/",paraId:6,tocIndex:1},{value:"Usage:",paraId:7,tocIndex:1},{value:"In ",paraId:8,tocIndex:1},{value:"GraphOptions.behaviors",paraId:8,tocIndex:1},{value:", for example:",paraId:8,tocIndex:1},{value:"const graph = new Graph({\n  // ... other options\n  behaviors: ['drag-canvas', 'zoom-canvas', 'drag-node'],\n});\n",paraId:9,tocIndex:1},{value:"Extension",paraId:10,tocIndex:3},{value:"Registration T